update member_info
set trust_score = (
	select 100 - (count(*) * 10)
	from (
		select mt.member_id as target_member_id
		from reports r		join meetups mt		on r.target_id = mt.meetup_id
		where r.target_type = 'MEETUP' and r.status = 'APPROVED'

		union all

		select rv.member_id as target_member_id
		from reports r		join reviews rv		on r.target_id = rv.review_id
		where r.target_type = 'REVIEW' and r.status = 'APPROVED'
	)
	where target_member_id = #{targetMemberId}
)
where member_id = #{targetMemberId}

update member_info
set report_status_id = #{reportStatusId}
where member_id = #{targetMemberId}

update reports
set status = #{status}
where report_id = #{reportId}
and status = 'PENDING'

